/**
 * Webhook notification adapter — delivers notifications via HTTP POST.
 *
 * Implements the NotificationAdapter interface with:
 * - JSON payload formatting
 * - URL validation
 * - Configurable retry logic
 * - Delivery tracking with sent webhook log
 *
 * In production, the default transport uses fetch(). In tests, swap
 * the transport layer via `setTransport()` to simulate failures.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationChannel, NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/** Configuration for the webhook adapter. */
export interface WebhookAdapterConfig {
  /** The target URL to POST notifications to. */
  url: string;
  /** Number of retry attempts on transient failures. */
  maxRetries: number;
}

const DEFAULT_CONFIG: WebhookAdapterConfig = {
  url: '',
  maxRetries: 2,
};

/** The JSON body sent to the webhook endpoint. */
export interface WebhookDelivery {
  url: string;
  payload: {
    type: string;
    recipient: string;
    subject: string;
    body: string;
    metadata?: Record<string, unknown>;
  };
  sentAt: Date;
  attempts: number;
}

export class WebhookAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'webhook';
  private logger = new Logger('WebhookAdapter');
  private config: WebhookAdapterConfig;
  private deliveries: WebhookDelivery[] = [];
  /** Optional hook to simulate transport failures in tests. */
  private transportFn: ((delivery: WebhookDelivery) => Promise<boolean>) | null = null;

  constructor(config?: Partial<WebhookAdapterConfig>) {
    this.config = { ...DEFAULT_CONFIG, ...config };
  }

  // ---------------------------------------------------------------------------
  // NotificationAdapter interface
  // ---------------------------------------------------------------------------

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    // 1. Validate URL
    const urlError = this.validateUrl(this.config.url);
    if (urlError) {
      this.logger.error(`Invalid webhook URL "${this.config.url}": ${urlError}`);
      return { success: false, channel: this.channel, error: urlError };
    }

    // 2. Format the delivery
    const delivery: WebhookDelivery = {
      url: this.config.url,
      payload: {
        type: payload.type,
        recipient: payload.recipient,
        subject: payload.subject,
        body: payload.body,
        metadata: payload.metadata,
      },
      sentAt: new Date(),
      attempts: 0,
    };

    // 3. Attempt delivery (with retries)
    const maxAttempts = this.config.maxRetries + 1;
    let lastError: string | undefined;

    for (let attempt = 1; attempt <= maxAttempts; attempt++) {
      delivery.attempts = attempt;
      try {
        const ok = await this.postWebhook(delivery);
        if (ok) {
          this.deliveries.push(delivery);
          this.logger.info(`Webhook delivered to ${this.config.url} (attempt ${attempt})`);
          return { success: true, channel: this.channel };
        }
        lastError = 'Webhook endpoint returned failure';
      } catch (err) {
        lastError = err instanceof Error ? err.message : String(err);
        this.logger.warn(
          `Webhook delivery attempt ${attempt}/${maxAttempts} failed for ${this.config.url}: ${lastError}`,
        );
      }
    }

    // All retries exhausted
    this.logger.error(`Webhook delivery failed for ${this.config.url} after ${maxAttempts} attempts: ${lastError}`);
    return { success: false, channel: this.channel, error: lastError };
  }

  // ---------------------------------------------------------------------------
  // URL validation
  // ---------------------------------------------------------------------------

  private validateUrl(url: string): string | null {
    if (!url || url.trim() === '') {
      return 'Webhook URL is required';
    }
    try {
      const parsed = new URL(url);
      if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
        return 'Webhook URL must use http or https protocol';
      }
      return null;
    } catch {
      return 'Invalid webhook URL format';
    }
  }

  // ---------------------------------------------------------------------------
  // Transport layer
  // ---------------------------------------------------------------------------

  /**
   * Internal webhook transport. By default this always succeeds (in-memory).
   * In production replace with a real HTTP POST call.
   * Use `setTransport()` in tests to simulate failures.
   */
  private async postWebhook(delivery: WebhookDelivery): Promise<boolean> {
    if (this.transportFn) {
      return this.transportFn(delivery);
    }
    // Default: successful in-memory delivery
    return true;
  }

  /**
   * Override the internal transport function. Useful in tests to simulate
   * transient failures, permanent failures, or latency.
   */
  setTransport(fn: (delivery: WebhookDelivery) => Promise<boolean>): void {
    this.transportFn = fn;
  }

  // ---------------------------------------------------------------------------
  // Inspection helpers (testing / debugging)
  // ---------------------------------------------------------------------------

  getDeliveries(): WebhookDelivery[] {
    return [...this.deliveries];
  }

  clearDeliveries(): void {
    this.deliveries = [];
  }

  getConfig(): WebhookAdapterConfig {
    return { ...this.config };
  }
}

