import { describe, it, expect, beforeEach } from 'vitest';
import { WebhookAdapter } from '../../src/adapters/webhook.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

describe('WebhookAdapter', () => {
  let adapter: WebhookAdapter;

  beforeEach(() => {
    adapter = new WebhookAdapter({ url: 'https://hooks.example.com/notify' });
  });

  // ---------------------------------------------------------------------------
  // Basic send
  // ---------------------------------------------------------------------------

  describe('send', () => {
    it('should successfully deliver a webhook', async () => {
      const payload: NotificationPayload = {
        type: 'order_confirmation',
        recipient: 'alice@example.com',
        subject: 'Order Confirmation: order-1',
        body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
        metadata: { orderId: 'order-1', userId: 'user-1' },
      };

      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.channel).toBe('webhook');
      expect(result.error).toBeUndefined();
    });

    it('should store delivery with correct fields', async () => {
      const payload: NotificationPayload = {
        type: 'order_confirmation',
        recipient: 'bob@example.com',
        subject: 'Order Confirmation: order-2',
        body: 'Your order has been placed.',
        metadata: { orderId: 'order-2' },
      };

      await adapter.send(payload);

      const deliveries = adapter.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.url).toBe('https://hooks.example.com/notify');
      expect(deliveries[0]?.payload.type).toBe('order_confirmation');
      expect(deliveries[0]?.payload.recipient).toBe('bob@example.com');
      expect(deliveries[0]?.payload.subject).toBe('Order Confirmation: order-2');
      expect(deliveries[0]?.payload.body).toBe('Your order has been placed.');
      expect(deliveries[0]?.payload.metadata).toEqual({ orderId: 'order-2' });
      expect(deliveries[0]?.sentAt).toBeInstanceOf(Date);
      expect(deliveries[0]?.attempts).toBe(1);
    });

    it('should report channel as webhook', () => {
      expect(adapter.channel).toBe('webhook');
    });

    it('should format payload as JSON-serializable object', async () => {
      const payload: NotificationPayload = {
        type: 'order_status_update',
        recipient: 'user@example.com',
        subject: 'Order Update',
        body: 'Status changed.',
        metadata: { orderId: 'order-5', newStatus: 'shipped' },
      };

      let capturedDelivery: unknown;
      adapter.setTransport(async (delivery) => {
        capturedDelivery = delivery;
        return true;
      });

      await adapter.send(payload);

      // The delivery payload should be JSON-round-trip safe
      const json = JSON.stringify(capturedDelivery);
      const parsed = JSON.parse(json);
      expect(parsed.payload.type).toBe('order_status_update');
      expect(parsed.payload.recipient).toBe('user@example.com');
      expect(parsed.payload.subject).toBe('Order Update');
      expect(parsed.payload.body).toBe('Status changed.');
      expect(parsed.payload.metadata.orderId).toBe('order-5');
    });
  });

  // ---------------------------------------------------------------------------
  // URL validation
  // ---------------------------------------------------------------------------

  describe('URL validation', () => {
    it('should reject empty URL', async () => {
      const noUrl = new WebhookAdapter({ url: '' });
      const result = await noUrl.send({
        type: 'welcome',
        recipient: 'user@example.com',
        subject: 'Welcome',
        body: 'Hello!',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('required');
      expect(noUrl.getDeliveries()).toHaveLength(0);
    });

    it('should reject missing URL (default config)', async () => {
      const noUrl = new WebhookAdapter();
      const result = await noUrl.send({
        type: 'welcome',
        recipient: 'user@example.com',
        subject: 'Welcome',
        body: 'Hello!',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('required');
    });

    it('should reject invalid URL format', async () => {
      const badUrl = new WebhookAdapter({ url: 'not-a-url' });
      const result = await badUrl.send({
        type: 'welcome',
        recipient: 'user@example.com',
        subject: 'Welcome',
        body: 'Hello!',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid webhook URL');
      expect(badUrl.getDeliveries()).toHaveLength(0);
    });

    it('should reject non-http/https protocols', async () => {
      const ftpUrl = new WebhookAdapter({ url: 'ftp://example.com/hook' });
      const result = await ftpUrl.send({
        type: 'welcome',
        recipient: 'user@example.com',
        subject: 'Test',
        body: 'Hello',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('http or https');
    });

    it('should accept valid http URL', async () => {
      const httpAdapter = new WebhookAdapter({ url: 'http://localhost:3000/webhooks' });
      const result = await httpAdapter.send({
        type: 'welcome',
        recipient: 'user@example.com',
        subject: 'Test',
        body: 'Hello',
      });

      expect(result.success).toBe(true);
    });

    it('should accept valid https URL', async () => {
      const result = await adapter.send({
        type: 'welcome',
        recipient: 'user@example.com',
        subject: 'Test',
        body: 'Hello',
      });

      expect(result.success).toBe(true);
    });
  });

  // ---------------------------------------------------------------------------
  // Configuration
  // ---------------------------------------------------------------------------

  describe('configuration', () => {
    it('should use default config when none provided', () => {
      const defaultAdapter = new WebhookAdapter();
      const config = defaultAdapter.getConfig();
      expect(config.url).toBe('');
      expect(config.maxRetries).toBe(2);
    });

    it('should accept custom config overrides', () => {
      const custom = new WebhookAdapter({
        url: 'https://custom.example.com/hook',
        maxRetries: 5,
      });

      const config = custom.getConfig();
      expect(config.url).toBe('https://custom.example.com/hook');
      expect(config.maxRetries).toBe(5);
    });
  });

  // ---------------------------------------------------------------------------
  // Retry logic
  // ---------------------------------------------------------------------------

  describe('retry logic', () => {
    it('should retry on transport failure', async () => {
      let callCount = 0;
      adapter.setTransport(async () => {
        callCount++;
        if (callCount < 3) {
          throw new Error('Connection timeout');
        }
        return true;
      });

      const result = await adapter.send({
        type: 'welcome',
        recipient: 'user@example.com',
        subject: 'Test',
        body: 'Hello',
      });

      expect(result.success).toBe(true);
      expect(callCount).toBe(3);
      expect(adapter.getDeliveries()[0]?.attempts).toBe(3);
    });

    it('should fail after all retries exhausted', async () => {
      adapter.setTransport(async () => {
        throw new Error('Permanent failure');
      });

      const result = await adapter.send({
        type: 'welcome',
        recipient: 'user@example.com',
        subject: 'Test',
        body: 'Hello',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Permanent failure');
      expect(adapter.getDeliveries()).toHaveLength(0);
    });

    it('should fail when transport returns false', async () => {
      adapter.setTransport(async () => false);

      const result = await adapter.send({
        type: 'welcome',
        recipient: 'user@example.com',
        subject: 'Test',
        body: 'Hello',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Webhook endpoint returned failure');
    });

    it('should respect maxRetries config', async () => {
      const noRetry = new WebhookAdapter({ url: 'https://hooks.example.com/notify', maxRetries: 0 });
      let callCount = 0;
      noRetry.setTransport(async () => {
        callCount++;
        throw new Error('fail');
      });

      await noRetry.send({
        type: 'welcome',
        recipient: 'user@example.com',
        subject: 'Test',
        body: 'Hello',
      });

      expect(callCount).toBe(1);
    });
  });

  // ---------------------------------------------------------------------------
  // Inspection helpers
  // ---------------------------------------------------------------------------

  describe('inspection helpers', () => {
    it('should clear deliveries', async () => {
      await adapter.send({
        type: 'welcome',
        recipient: 'user@example.com',
        subject: 'Test',
        body: 'Hello',
      });

      expect(adapter.getDeliveries()).toHaveLength(1);
      adapter.clearDeliveries();
      expect(adapter.getDeliveries()).toHaveLength(0);
    });

    it('should return a copy of deliveries', async () => {
      await adapter.send({
        type: 'welcome',
        recipient: 'user@example.com',
        subject: 'Test',
        body: 'Hello',
      });

      const deliveries1 = adapter.getDeliveries();
      const deliveries2 = adapter.getDeliveries();
      expect(deliveries1).not.toBe(deliveries2);
      expect(deliveries1).toEqual(deliveries2);
    });
  });

  // ---------------------------------------------------------------------------
  // Integration with NotificationService pattern
  // ---------------------------------------------------------------------------

  describe('NotificationAdapter interface compliance', () => {
    it('should have a channel property', () => {
      expect(adapter.channel).toBe('webhook');
    });

    it('should have an async send method that returns NotificationResult', async () => {
      const result = await adapter.send({
        type: 'welcome',
        recipient: 'user@example.com',
        subject: 'Test',
        body: 'Hello',
      });

      expect(result).toHaveProperty('success');
      expect(result).toHaveProperty('channel');
      expect(typeof result.success).toBe('boolean');
      expect(result.channel).toBe('webhook');
    });
  });

  // ---------------------------------------------------------------------------
  // Registration with NotificationService
  // ---------------------------------------------------------------------------

  describe('registration with NotificationService', () => {
    it('should be registrable with notification service', async () => {
      // Import dynamically to avoid circular dependencies in test setup
      const { EventBus } = await import('../../src/events/event-bus.js');
      const { NotificationService } = await import('../../src/services/notification.service.js');

      const eventBus = new EventBus();
      const notificationService = new NotificationService(eventBus);

      // Should not throw when registering
      notificationService.registerAdapter(adapter);

      // Verify webhook delivery works through the service
      const payload: NotificationPayload = {
        type: 'order_confirmation',
        recipient: 'user@example.com',
        subject: 'Test Order',
        body: 'Order placed.',
        metadata: { orderId: 'order-99', userId: 'user-1' },
      };

      // Trigger via event
      eventBus.emit('order:created', {
        type: 'order:created',
        timestamp: new Date(),
        order: {
          id: 'order-99',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, price: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: { id: 'user-1', email: 'user@example.com', name: 'Test User', createdAt: new Date(), updatedAt: new Date() },
      });

      // Allow async event handlers to complete
      await new Promise((resolve) => setTimeout(resolve, 50));

      const deliveries = adapter.getDeliveries();
      expect(deliveries.length).toBeGreaterThanOrEqual(1);
      expect(deliveries[0]?.payload.type).toBe('order_confirmation');

      const notifications = notificationService.getNotifications();
      const webhookNotifs = notifications.filter((n) => n.channel === 'webhook');
      expect(webhookNotifs.length).toBeGreaterThanOrEqual(1);
      expect(webhookNotifs[0]?.status).toBe('sent');
    });
  });
});

